import{_ as e,c as r,o as a,ag as o}from"./chunks/framework.DPDPlp3K.js";const f=JSON.parse('{"title":"共同開発のすすめ","description":"","frontmatter":{},"headers":[],"relativePath":"text/chapter-2/best-practice.md","filePath":"text/chapter-2/best-practice.md"}'),c={name:"text/chapter-2/best-practice.md"};function s(d,t,l,n,i,p){return a(),r("div",null,t[0]||(t[0]=[o('<h1 id="共同開発のすすめ" tabindex="-1">共同開発のすすめ <a class="header-anchor" href="#共同開発のすすめ" aria-label="Permalink to &quot;共同開発のすすめ&quot;">​</a></h1><p>最後に、統制の効いた共同開発においてはコミットメッセージやブランチ名、その他の Git や Gitea の扱いにどんなルールが定められているのか、よくある例をいくつか紹介します。</p><p>この章の内容の実践が個人開発やハッカソンの共同開発において強制されることは普通ありません。まずはそんなことを気にせず積極的に開発に参加するのがよいです。その上で、責任ある開発の現場でどんなルールが採用されているのかについて少しでも知っておくと、その知識が普段の開発にも何か示唆を与えてくれるかも知れません。</p><div class="info custom-block"><p class="custom-block-title">Git 講習会中級編</p><p>たけのひとさんによって 2024 年度に開催された <a href="https://q.trap.jp/files/151ef5c6-000e-4477-b767-07cf44fda757" target="_blank" rel="noreferrer">Git 講習会中級編</a> では、プロジェクトやハッカソンのチームリーダー向けにさらに発展的な内容を取り扱っています。興味があればぜひ資料を確認してみてください。</p></div><h2 id="接頭辞" tabindex="-1">接頭辞 <a class="header-anchor" href="#接頭辞" aria-label="Permalink to &quot;接頭辞&quot;">​</a></h2><p>コミットメッセージやブランチ名の頭に決まった種類の接頭辞をつけることで、そのコミットやブランチの意図の分類を明確にすることが出来ます。たとえば以下がよく使われます。</p><table style="width:100%;border-collapse:collapse;"><thead><tr><th style="width:auto;text-align:center;">接頭辞</th><th style="width:100%;">一般的な意味合い</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>feat</strong></td><td>新機能の追加</td></tr><tr><td style="text-align:center;"><strong>fix</strong></td><td>既存の機能の問題修正</td></tr><tr><td style="text-align:center;"><strong>hotfix</strong></td><td>緊急の問題修正</td></tr><tr><td style="text-align:center;"><strong>style</strong></td><td>コードのスタイル変更やフォーマット</td></tr><tr><td style="text-align:center;"><strong>docs</strong></td><td>ドキュメントの変更</td></tr><tr><td style="text-align:center;"><strong>chore</strong></td><td>コードやドキュメントに影響しない作業</td></tr><tr><td style="text-align:center;"><strong>refactor</strong></td><td>リファクタリング（コードの整頓）</td></tr></tbody></table><p>コミットメッセージに接頭辞をつける場合は <code>feat: コミットメッセージ</code> のように、ブランチ名に接頭辞をつける場合は <code>feat/リポジトリ名</code> のように書くことが一般的です。traQ フロントエンドリポジトリの <a href="https://github.com/traPtitech/traQ_S-UI/branches/all" target="_blank" rel="noreferrer">Branches</a> と <a href="https://github.com/traPtitech/traQ_S-UI/commits/master/" target="_blank" rel="noreferrer">Commits</a> で実例を確認してみましょう。</p><div class="info custom-block"><p class="custom-block-title">ブランチ名に含まれるスラッシュ</p><p>Git ではブランチ名にスラッシュ <code>/</code> を含めることができます。このスラッシュはディレクトリのパスに含まれる <code>/</code> に似た振る舞いを示し、たとえばすでに <code>feat/ーーを追加</code> という名のブランチが存在する場合は新たに <code>feat</code> という名前のブランチを作ることが許されなくなります。</p></div><div class="danger custom-block"><p class="custom-block-title">ネタ切れ発生</p><p>ここに書くことを募集しています</p></div>',10)]))}const g=e(c,[["render",s]]);export{f as __pageData,g as default};
